import React, { useState, useEffect, useCallback } from 'react';
import { useAppContext } from '../context/AppContext'; // ✅ Импортируем контекст
import { api } from '../services/api';
import DashboardHeader from '../components/Dashboard/DashboardHeader';
import KpiCards from '../components/Dashboard/KpiCards';
import LogisticsChart from '../components/Dashboard/LogisticsChart'; // Предположим, есть такой компонент
import LogisticsTable from '../components/Dashboard/LogisticsTable';
import ExportButton from '../components/Export/ExportButton';
import Button from '../components/UI/Button';

const LogisticsDashboard = () => {
  const { period, logistics } = useAppContext(); // ✅ Читаем из контекста
  const [logisticsData, setLogisticsData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [loadingError, setLoadingError] = useState(null);

  // ✅ Обернём в useCallback
  const fetchData = useCallback(async () => {
    setLoading(true);
    setLoadingError(null);
    try {
      // ✅ Передаём period и logistics в API
      const data = await api.getLogisticsData(period, logistics);
      setLogisticsData(data);
    } catch (error) {
      console.error("Failed to fetch logistics data", error);
      if (error.status === 404) {
        setLogisticsData(null);
      } else {
        setLoadingError(error.message || "Не удалось загрузить данные");
      }
    } finally {
      setLoading(false);
    }
  }, [period, logistics]); // ✅ Зависимости

  useEffect(() => {
    fetchData();
  }, [fetchData]); // ✅ Зависимость от fetchData

  if (loading) {
    return <div className="p-6">Загрузка данных логистики...</div>;
  }

  if (loadingError) {
    return (
      <div className="p-6 text-center">
        <p className="text-red-600 dark:text-red-400">Ошибка: {loadingError}</p>
        <Button onClick={fetchData} className="mt-4">Повторить попытку</Button>
      </div>
    );
  }

  if (!logisticsData) {
    return (
      <div className="p-6 text-center">
        <h1 className="text-2xl font-bold mb-4">Логистика</h1>
        <p className="text-gray-600 dark:text-gray-400 mb-6">
          Данные отсутствуют. Нажмите кнопку ниже, чтобы синхронизировать данные с Ozon.
        </p>
        <Button onClick={fetchData}>🔄 Синхронизировать данные</Button>
      </div>
    );
  }

  return (
    <div className="p-6">
      <div className="flex justify-between items-center mb-4">
        <h1 className="text-2xl font-bold">Логистика</h1>
        <ExportButton data={logisticsData} scope="logistics" period={period} logistics={logistics} />
      </div>
      <DashboardHeader /> {/* ✅ Используем общий хедер */}
      {/* Отображаем KPI, графики, таблицы */}
      <KpiCards data={logisticsData} />
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6">
        <div className="bg-white dark:bg-gray-800 p-4 rounded-lg shadow">
          <h2 className="text-lg font-semibold mb-4">График по логистике</h2>
          <LogisticsChart data={logisticsData} />
        </div>
        <div className="bg-white dark:bg-gray-800 p-4 rounded-lg shadow">
          <h2 className="text-lg font-semibold mb-4">Таблица по логистике</h2>
          <LogisticsTable data={logisticsData} />
        </div>
      </div>
    </div>
  );
};

export default LogisticsDashboard;
